(function(){let e=document.createElement(`link`).relList;if(e&&e.supports&&e.supports(`modulepreload`))return;for(let e of document.querySelectorAll(`link[rel="modulepreload"]`))n(e);new MutationObserver(e=>{for(let t of e)if(t.type===`childList`)for(let e of t.addedNodes)e.tagName===`LINK`&&e.rel===`modulepreload`&&n(e)}).observe(document,{childList:!0,subtree:!0});function t(e){let t={};return e.integrity&&(t.integrity=e.integrity),e.referrerPolicy&&(t.referrerPolicy=e.referrerPolicy),e.crossOrigin===`use-credentials`?t.credentials=`include`:e.crossOrigin===`anonymous`?t.credentials=`omit`:t.credentials=`same-origin`,t}function n(e){if(e.ep)return;e.ep=!0;let n=t(e);fetch(e.href,n)}})();var e=[{id:`zhenhuan`,name:`甄嬛型`,role:`甄嬛`,title:`聪慧坚韧的宫廷智者`,image:`assets/characters/zhenhuan.png`,keywords:[`聪慧`,`坚韧`,`隐忍`,`谋略`,`成长型`],analysis:`你拥有甄嬛式的智慧与韧性。初入宫廷时天真烂漫，经历风雨后逐渐成长为深谋远虑的宫廷智者。你善于在逆境中寻找机会，懂得审时度势，能够在复杂的环境中保护自己并最终达成目标。你的成长轨迹证明了"不经一番寒彻骨，怎得梅花扑鼻香"。`,characterAnalysis:`甄嬛从天真少女成长为太后，经历了从单纯到深沉的蜕变。她既有善良温柔的一面，也有果断狠辣的一面。在权力斗争中，她学会了利用规则、借力打力，最终成为后宫最大的赢家。这与你在生活中展现出的适应能力和成长潜力高度契合。`,shareText:`我测出了【甄嬛型人格】——聪慧坚韧的宫廷智者。不经一番寒彻骨，怎得梅花扑鼻香。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:4,emotion:3,social:4,stress:5,moral:3}},{id:`huafei`,name:`华妃型`,role:`华妃`,title:`骄傲热烈的宫廷玫瑰`,image:`assets/characters/huafei.png`,keywords:[`骄傲`,`热烈`,`直率`,`专情`,`悲剧美`],analysis:`你拥有华妃式的骄傲与热烈。你敢爱敢恨，从不掩饰自己的情感与野心。你的骄傲源于真实的实力与家世，你的热烈源于对爱情的执着追求。虽然有时过于直率会带来麻烦，但你的真诚与热情也让你成为人群中最耀眼的存在。`,characterAnalysis:`华妃年世兰是后宫中最骄傲的存在，她的骄傲源于年家的权势和皇帝的宠爱。她爱得热烈，恨得彻底，从不屑于玩弄心机。她的悲剧在于过于依赖外在的权力和爱情，当这些失去时，她选择了以死明志。这提醒你在追求目标时也要保持内心的独立。`,shareText:`我测出了【华妃型人格】——骄傲热烈的宫廷玫瑰。贱人就是矫情，但本宫就是喜欢这样活着。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:5,emotion:5,social:2,stress:2,moral:2}},{id:`shenmeizhuang`,name:`沈眉庄型`,role:`沈眉庄`,title:`温婉坚定的清流君子`,image:`characters/shenmeizhuang.png`,keywords:[`温婉`,`坚定`,`清高`,`重情`,`傲骨`],analysis:`你拥有沈眉庄式的温婉与坚定。你外表温和大方，内心却有着不可动摇的原则与傲骨。你看重真情，不屑于虚伪的社交游戏。当被伤害后，你选择保持距离而非报复，这种清高的姿态让你在复杂的环境中保持着内心的纯净。`,characterAnalysis:`沈眉庄是后宫中难得的清流，她出身名门，知书达理，却不愿随波逐流。被皇帝误解后，她选择了冷眼旁观，将真心给了值得的人。她与甄嬛的友情是后宫中最真挚的情感之一。她的故事告诉我们，保持本心比获得权力更重要。`,shareText:`我测出了【沈眉庄型人格】——温婉坚定的清流君子。宁可枝头抱香死，何曾吹落北风中。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:2,emotion:4,social:3,stress:3,moral:5}},{id:`anlingrong`,name:`安陵容型`,role:`安陵容`,title:`敏感多疑的悲剧灵魂`,image:`assets/characters/anlingrong.png`,keywords:[`敏感`,`自卑`,`多疑`,`才华`,`悲剧`],analysis:`你拥有安陵容式的敏感与才华。你内心细腻，善于观察，有着不输他人的才华与能力。然而，过度的敏感和自卑让你容易陷入自我怀疑，对他人的善意也常产生误解。学会接纳自己、信任他人，是你人生的重要课题。`,characterAnalysis:`安陵容出身低微，却有着不输他人的才华。她的悲剧源于深深的自卑和对他人善意的误解。她本可以与甄嬛成为挚友，却因多疑和嫉妒走向了对立面。她的故事警示我们，自卑和猜疑会毁掉最美好的可能性。`,shareText:`我测出了【安陵容型人格】——敏感多疑的悲剧灵魂。人生若只如初见，何事秋风悲画扇。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:3,emotion:2,social:2,stress:2,moral:2}},{id:`huanghou`,name:`皇后型`,role:`皇后`,title:`深沉隐忍的权力掌控者`,image:`assets/characters/huanghou.png`,keywords:[`深沉`,`隐忍`,`权谋`,`母仪`,`悲剧`],analysis:`你拥有皇后式的深沉与隐忍。你善于隐藏真实情感，在表面温和的背后运筹帷幄。你追求权力和地位，但你的手段往往更加隐蔽和长远。你的悲剧在于，为了权力你牺牲了太多，包括真实的自我和纯粹的情感。`,characterAnalysis:`皇后宜修是后宫中最深沉的存在，她表面母仪天下，实则心机深沉。她的悲剧在于，为了保住皇后的位置，她失去了做母亲和做妻子的资格。她的一生都在算计中度过，最终却输给了更年轻的甄嬛。这提醒我们，权力不是人生的全部。`,shareText:`我测出了【皇后型人格】——深沉隐忍的权力掌控者。臣妾做不到啊，但臣妾必须做到。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:5,emotion:2,social:4,stress:4,moral:1}},{id:`jingfei`,name:`敬妃型`,role:`敬妃`,title:`淡泊明哲的生存智者`,image:`characters/jingfei.png`,keywords:[`淡泊`,`明哲`,`稳重`,`可靠`,`智慧`],analysis:`你拥有敬妃式的淡泊与智慧。你不争不抢，却能在宫廷的风云变幻中安然生存。你懂得审时度势，知道何时该进、何时该退。你的稳重和可靠让你成为他人信赖的对象，你的淡泊让你在名利场中保持着内心的平静。`,characterAnalysis:`敬妃是后宫中最清醒的存在，她从不参与争斗，却能在每一次风波中全身而退。她收养胧月公主，与甄嬛结盟，最终成为太妃，安享晚年。她的故事告诉我们，有时候不争才是最大的智慧。`,shareText:`我测出了【敬妃型人格】——淡泊明哲的生存智者。不争不抢，自有天意。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:2,emotion:3,social:4,stress:5,moral:4}},{id:`guojunwang`,name:`果郡王型`,role:`果郡王`,title:`深情浪漫的理想主义者`,image:`characters/guojunwang.png`,keywords:[`深情`,`浪漫`,`理想`,`才华`,`牺牲`],analysis:`你拥有果郡王式的深情与浪漫。你追求纯粹的爱情和理想，愿意为所爱之人付出一切。你的浪漫和才华让你在人群中独具魅力，但你的理想主义有时会让你与现实产生冲突。你的深情是珍贵的，但也要学会保护自己。`,characterAnalysis:`果郡王允礼是剧中最深情的男性角色，他对甄嬛的爱纯粹而炽热。他才华横溢，风度翩翩，却因爱情而卷入宫廷斗争，最终为爱牺牲。他的故事告诉我们，纯粹的爱情是珍贵的，但在现实面前也需要智慧和分寸。`,shareText:`我测出了【果郡王型人格】——深情浪漫的理想主义者。愿得一心人，白首不相离。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:1,emotion:5,social:3,stress:2,moral:5}},{id:`yelanyi`,name:`叶澜依型`,role:`叶澜依`,title:`桀骜不驯的自由灵魂`,image:`characters/yelanyi.png`,keywords:[`桀骜`,`自由`,`专情`,`勇敢`,`洒脱`],analysis:`你拥有叶澜依式的桀骜与自由。你不愿被世俗规则束缚，追求内心的真实和自由。你敢爱敢恨，为所爱之人可以付出一切。你的洒脱和勇敢让你在人群中独树一帜，但有时也会让你显得格格不入。`,characterAnalysis:`叶澜依是后宫中最特别的存在，她本是驯马女，因酷似华妃而被纳入后宫。她从不掩饰对皇帝的厌恶，却对果郡王怀有深深的爱意。她最终为果郡王报仇，选择了自我了断。她的故事告诉我们，真正的自由来自于内心的坚守。`,shareText:`我测出了【叶澜依型人格】——桀骜不驯的自由灵魂。我命由我不由天。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:1,emotion:5,social:1,stress:3,moral:4}},{id:`huanbi`,name:`浣碧型`,role:`浣碧`,title:`心高气傲的奋斗者`,image:`characters/huanbi.png`,keywords:[`心高`,`奋斗`,`嫉妒`,`渴望`,`悲剧`],analysis:`你拥有浣碧式的心高与奋斗。你渴望被认可，渴望获得与身份匹配的地位和尊重。你努力奋斗，不甘心屈居人下。然而，过度的嫉妒和攀比有时会让你做出错误的选择。学会接纳自己的出身，找到真正属于自己的道路。`,characterAnalysis:`浣碧是甄嬛的同父异母妹妹，却因私生女的身份只能做丫鬟。她心高气傲，不甘心低人一等，曾一度背叛甄嬛。最终她嫁给了果郡王，却在果郡王死后随之而去。她的悲剧在于，她一生都在追求一个不属于自己的位置。`,shareText:`我测出了【浣碧型人格】——心高气傲的奋斗者。我命由我不由天，但天意弄人。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:4,emotion:3,social:2,stress:3,moral:2}},{id:`cuijinxi`,name:`崔槿汐型`,role:`崔槿汐`,title:`忠诚智慧的守护者`,image:`characters/cuijinxi.png`,keywords:[`忠诚`,`智慧`,`稳重`,`可靠`,`深情`],analysis:`你拥有崔槿汐式的忠诚与智慧。你是他人最可靠的伙伴，懂得在关键时刻给予支持和建议。你的智慧来自于丰富的阅历，你的忠诚来自于内心的坚定。你愿意为所爱之人付出一切，同时也懂得保护自己。`,characterAnalysis:`崔槿汐是甄嬛最信任的侍女，也是她最可靠的伙伴。她智慧过人，忠诚坚定，在甄嬛最困难的时候始终陪伴左右。她与苏培盛的感情也是剧中难得的温暖。她的故事告诉我们，真正的忠诚来自于内心的选择，而非外在的约束。`,shareText:`我测出了【崔槿汐型人格】——忠诚智慧的守护者。士为知己者死，女为悦己者容。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:2,emotion:4,social:5,stress:4,moral:5}},{id:`duanfei`,name:`端妃型`,role:`端妃`,title:`隐忍坚韧的沉默智者`,image:`characters/duanfei.png`,keywords:[`隐忍`,`坚韧`,`沉默`,`智慧`,`复仇`],analysis:`你拥有端妃式的隐忍与坚韧。你能在最艰难的环境中默默承受，等待时机的到来。你的沉默不是软弱，而是积蓄力量的方式。当机会来临时，你会以最精准的方式达成目标。你的坚韧让你成为最后的赢家之一。`,characterAnalysis:`端妃是后宫中最隐忍的存在，她被华妃陷害而终身不孕，却默默忍受了多年。她与甄嬛结盟，最终见证了华妃和皇后的倒台。她的故事告诉我们，有时候沉默和等待是最强大的武器。`,shareText:`我测出了【端妃型人格】——隐忍坚韧的沉默智者。君子报仇，十年不晚。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:3,emotion:2,social:3,stress:5,moral:3}},{id:`wenshichu`,name:`温实初型`,role:`温实初`,title:`深情守护的默默付出者`,image:`assets/characters/wenshichu.png`,keywords:[`深情`,`守护`,`付出`,`医者`,`悲剧`],analysis:`你拥有温实初式的深情与守护。你愿意默默守护所爱之人，不求回报，只愿她安好。你的付出是无私的，但有时也会让你忽略自己的感受。学会在付出的同时也关爱自己，才能拥有更健康的关系。`,characterAnalysis:`温实初是甄嬛的青梅竹马，一生都在默默守护她。他作为太医，多次在关键时刻帮助甄嬛。他最终与沈眉庄相爱，却在眉庄死后选择了自宫。他的故事告诉我们，深情是珍贵的，但也要学会为自己而活。`,shareText:`我测出了【温实初型人格】——深情守护的默默付出者。愿得一人心，白首不相离。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:1,emotion:5,social:3,stress:3,moral:5}},{id:`yongzheng`,name:`雍正型`,role:`雍正`,title:`深沉多疑的权力掌控者`,image:`characters/yongzheng.png`,keywords:[`深沉`,`多疑`,`权力`,`孤独`,`帝王`],analysis:`你拥有雍正式的深沉与多疑。你追求权力和掌控，善于在复杂的局势中运筹帷幄。你的深沉让你难以被看透，你的多疑让你难以真正信任他人。你的成功来自于对权力的执着，但你的孤独也源于此。`,characterAnalysis:`雍正是整个故事的核心，他深沉多疑，对权力有着极度的渴望。他可以宠爱一个女人，也可以在瞬间将她打入冷宫。他的悲剧在于，他拥有天下，却从未拥有真正的爱情和信任。他的故事告诉我们，权力和孤独往往相伴而生。`,shareText:`我测出了【雍正型人格】——深沉多疑的权力掌控者。朕即天下，但天下无人懂朕。你也来测测看你是《甄嬛传》里的谁？`,weights:{power:5,emotion:1,social:2,stress:4,moral:2}}],t={};document.addEventListener(`DOMContentLoaded`,function(){r(),i(),a(),n()});function n(){t={},e.forEach(e=>{t[e.id]=0})}function r(){let e=document.getElementById(`particles`);if(e)for(let t=0;t<25;t++){let t=document.createElement(`div`);t.className=`particle`;let n=Math.random()*5+3;t.style.width=n+`px`,t.style.height=n+`px`,t.style.left=Math.random()*100+`%`,t.style.top=Math.random()*100+`%`,t.style.animationDelay=Math.random()*4+`s`,t.style.animationDuration=Math.random()*3+4+`s`,e.appendChild(t)}}function i(){let e=document.getElementById(`petals`);if(e)for(let t=0;t<18;t++){let t=document.createElement(`div`);t.className=`petal`,t.style.left=Math.random()*100+`%`,t.style.top=Math.random()*100+`%`,t.style.animationDelay=Math.random()*6+`s`,t.style.animationDuration=Math.random()*5+6+`s`,t.style.transform=`rotate(`+Math.random()*360+`deg)`,e.appendChild(t)}}function a(){let t=document.getElementById(`personalitySwiper`);if(!t)return;e.forEach((e,n)=>{let r=document.createElement(`div`);r.className=`persona-card glass-card gold-outline`+(n===0?` active`:``),r.innerHTML=`
      <img src="${e.image}" alt="${e.name}" class="persona-image" onerror="this.style.display='none'">
      <div class="persona-info">
        <h3 class="title-md text-gold">${e.name}</h3>
        <p class="persona-role">${e.title}</p>
        <div class="persona-tags">
          ${e.keywords.map(e=>`<span class="persona-tag">${e}</span>`).join(``)}
        </div>
      </div>
    `,t.appendChild(r)});let n=0;setInterval(()=>{let r=t.querySelectorAll(`.persona-card`);r[n].classList.remove(`active`),r[n].classList.add(`prev`),n=(n+1)%e.length,r.forEach((e,t)=>{t!==n&&e.classList.remove(`prev`)}),r[n].classList.add(`active`)},3500)}